package com.example.alcoholictimer

import android.content.Context
import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.tooling.preview.Preview
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import java.text.SimpleDateFormat
import java.util.*
import kotlin.math.roundToInt

/**
 * кёҲмЈј кё°лЎқ м№ҙл“ңмқҳ мғҒм„ё м •ліҙлҘј н‘ңмӢңн•ҳлҠ” м•ЎнӢ°л№„нӢ°
 * DetailActivityмҷҖ кө¬л¶„н•ҳм—¬ м№ҙл“ң нҒҙлҰӯ мӢң н‘ңмӢңлҗҳлҠ” нҷ”л©ҙмңјлЎң мӮ¬мҡ©
 */
class CardDetailActivity : ComponentActivity() {

    companion object {
        private const val TAG = "CardDetailActivity"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        Log.d(TAG, "===== CardDetailActivity onCreate мӢңмһ‘ =====")

        try {
            // Intentм—җм„ң лҚ°мқҙн„° л°ӣкё° (м•Ҳм „н•ң л°©мӢқмңјлЎң)
            val startTime = intent.getLongExtra("start_time", 0L)
            val endTime = intent.getLongExtra("end_time", System.currentTimeMillis())
            val targetDays = intent.getFloatExtra("target_days", 30f)
            val actualDays = intent.getIntExtra("actual_days", 0)
            val isCompleted = intent.getBooleanExtra("is_completed", false)

            Log.d(TAG, "мҲҳмӢ лҗң лҚ°мқҙн„°: startTime=$startTime, endTime=$endTime, targetDays=$targetDays, actualDays=$actualDays, isCompleted=$isCompleted")

            // лҚ°мқҙн„° мң нҡЁм„ұ кІҖмӮ¬ (мЎ°кұҙ мҷ„нҷ”)
            if (actualDays < 0 || targetDays < 0) {
                Log.e(TAG, "мһҳлӘ»лҗң лҚ°мқҙн„°: actualDays=$actualDays, targetDays=$targetDays")
                finish()
                return
            }

            // targetDaysк°Җ 0мқё кІҪмҡ° кё°ліёк°’мңјлЎң м„Өм •
            val safetargetDays = if (targetDays <= 0) 30f else targetDays
            Log.d(TAG, "м•Ҳм „н•ң targetDays к°’: $safetargetDays")

            Log.d(TAG, "setContent нҳём¶ң мӢңмһ‘...")
            setContent {
                CardDetailScreen(
                    startTime = startTime,
                    endTime = endTime,
                    targetDays = safetargetDays,
                    actualDays = actualDays,
                    isCompleted = isCompleted,
                    onBack = {
                        Log.d(TAG, "л’ӨлЎңк°Җкё° лІ„нҠј нҒҙлҰӯ")
                        finish()
                    }
                )
            }
            Log.d(TAG, "setContent нҳём¶ң мҷ„лЈҢ")
            Log.d(TAG, "===== CardDetailActivity onCreate мҷ„лЈҢ =====")
        } catch (e: Exception) {
            Log.e(TAG, "CardDetailActivity мҙҲкё°нҷ” мӨ‘ мҳӨлҘҳ", e)
            Log.e(TAG, "мҳӨлҘҳ мҠӨнғқнҠёл ҲмқҙмҠӨ: ${e.stackTraceToString()}")
            finish()
        }
    }
}

@Composable
fun CardDetailScreen(
    startTime: Long,
    endTime: Long,
    targetDays: Float,
    actualDays: Int,
    isCompleted: Boolean,
    onBack: () -> Unit
) {
    val context = LocalContext.current

    // лӮ м§ң/мӢңк°„ нҸ¬л§·
    val dateTimeFormat = SimpleDateFormat("yyyy-MM-dd - a h:mm", Locale.getDefault())
    val displayDateTime = if (startTime > 0) {
        dateTimeFormat.format(Date(startTime))
    } else {
        "мҳӨлҠҳ - ${SimpleDateFormat("a h:mm", Locale.getDefault()).format(Date())}"
    }

    // кё°лЎқ м ңлӘ© мһҗлҸҷ мғқм„ұ
    val recordTitle = if (isCompleted) {
        "кёҲмЈј ${actualDays}мқј лӢ¬м„ұ кё°лЎқ"
    } else {
        "кёҲмЈј ${actualDays}мқјм°Ё мӨ‘лӢЁ кё°лЎқ"
    }

    // кёҲмЈј кё°к°„ кі„мӮ°
    val totalDuration = if (startTime > 0) {
        ((endTime - startTime) / (24 * 60 * 60 * 1000)).toInt()
    } else {
        actualDays
    }

    // м„Өм •к°’ к°Җм ёмҳӨкё° (м Ҳм•Ҫ кёҲм•Ў/мӢңк°„ кі„мӮ°мҡ©)
    val sharedPref = context.getSharedPreferences("user_settings", Context.MODE_PRIVATE)
    val selectedCost = sharedPref.getString("selected_cost", "мӨ‘") ?: "мӨ‘"
    val selectedFrequency = sharedPref.getString("selected_frequency", "мЈј 2~3нҡҢ") ?: "мЈј 2~3нҡҢ"
    val selectedDuration = sharedPref.getString("selected_duration", "ліҙнҶө") ?: "ліҙнҶө"

    // м Ҳм•Ҫ кёҲм•Ў/мӢңк°„ кі„мӮ°
    val costVal = when(selectedCost) {
        "м Җ" -> 10000
        "мӨ‘" -> 40000
        "кі " -> 70000
        else -> 40000
    }

    val freqVal = when(selectedFrequency) {
        "мЈј 1нҡҢ мқҙн•ҳ" -> 1.0
        "мЈј 2~3нҡҢ" -> 2.5
        "мЈј 4нҡҢ мқҙмғҒ" -> 5.0
        else -> 2.5
    }

    val drinkHoursVal = when(selectedDuration) {
        "м§§мқҢ" -> 2
        "ліҙнҶө" -> 4
        "к№Җ" -> 6
        else -> 4
    }

    val hangoverHoursVal = 5
    val weeks = actualDays / 7.0
    val savedMoney = (weeks * freqVal * costVal).roundToInt()
    val savedHours = (weeks * freqVal * (drinkHoursVal + hangoverHoursVal)).roundToInt()

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
            .padding(24.dp)
    ) {
        // н—ӨлҚ” мҳҒм—ӯ
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // л’ӨлЎңк°Җкё° лІ„нҠј
            Box(
                contentAlignment = Alignment.Center,
                modifier = Modifier
                    .size(40.dp)
                    .background(Color.LightGray, CircleShape)
                    .clickable { onBack() }
            ) {
                Text(
                    text = "вҶҗ",
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Bold
                )
            }

            Text(
                text = "кёҲмЈј кё°лЎқ мғҒм„ё",
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold
            )

            Spacer(modifier = Modifier.width(40.dp)) // к· нҳ• л§һм¶”кё°
        }

        Spacer(modifier = Modifier.height(32.dp))

        // лӮ м§ң л°Ҹ мӢңк°„
        Text(
            text = displayDateTime,
            fontSize = 16.sp,
            color = Color.Gray,
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        // кё°лЎқ м ңлӘ©
        Text(
            text = recordTitle,
            fontSize = 20.sp,
            fontWeight = FontWeight.Bold,
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(40.dp))

        // мЈјмҡ” нҶөкі„ мҳҒм—ӯ
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            // мҷјмӘҪ лҢҖнҳ• мҲ«мһҗ
            Column(
                modifier = Modifier.weight(1f),
                horizontalAlignment = Alignment.Start
            ) {
                Text(
                    text = actualDays.toString(),
                    fontSize = 72.sp,
                    fontWeight = FontWeight.Bold,
                    color = Color.Black,
                    lineHeight = 72.sp
                )
                Text(
                    text = "мқј",
                    fontSize = 16.sp,
                    color = Color.Gray
                )
            }

            // мҳӨлҘёмӘҪ м„ұм·Ё м•„мқҙмҪҳ
            Column(
                modifier = Modifier.weight(1f),
                horizontalAlignment = Alignment.End
            ) {
                Text(
                    text = if (isCompleted) "" else "вҸёпёҸ",
                    fontSize = 60.sp
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = if (isCompleted) "лӘ©н‘ң лӢ¬м„ұ" else "мӨ‘лӢЁлҗЁ",
                    fontSize = 14.sp,
                    color = if (isCompleted) Color(0xFF4CAF50) else Color(0xFFFF9800),
                    fontWeight = FontWeight.Bold
                )
            }
        }

        Spacer(modifier = Modifier.height(32.dp))

        // м„ңлёҢ нҶөкі„ (2мӨ„ л°°м№ҳ)
        Column {
            // мІ« лІҲм§ё мӨ„
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceEvenly
            ) {
                CardSubStatItem(
                    value = "${totalDuration}мқј",
                    label = "мҙқ кёҲмЈј кё°к°„",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = String.format(Locale.getDefault(), "%,dмӣҗ", savedMoney),
                    label = "м Ҳм•Ҫн•ң кёҲм•Ў",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = "${savedHours}мӢңк°„",
                    label = "м Ҳм•Ҫн•ң мӢңк°„",
                    modifier = Modifier.weight(1f)
                )
            }

            Spacer(modifier = Modifier.height(24.dp))

            // л‘җ лІҲм§ё мӨ„
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceEvenly
            ) {
                CardSubStatItem(
                    value = "${((actualDays.toFloat() / targetDays) * 100).roundToInt()}%",
                    label = "лӘ©н‘ң лӢ¬м„ұлҘ ",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = getLevelName(actualDays),
                    label = "лӢ¬м„ұ л ҲлІЁ",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = "${(actualDays / 30.0).roundToInt()}мқј",
                    label = "кё°лҢҖ мҲҳлӘ… мҰқк°Җ",
                    modifier = Modifier.weight(1f)
                )
            }
        }

        Spacer(modifier = Modifier.weight(1f))

        // н•ҳлӢЁ лІ„нҠј
        Button(
            onClick = { onBack() },
            modifier = Modifier
                .fillMaxWidth()
                .height(56.dp),
            colors = ButtonDefaults.buttonColors(
                containerColor = Color.Black
            )
        ) {
            Text(
                text = "нҷ•мқё",
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold,
                color = Color.White
            )
        }
    }
}

@Composable
private fun CardSubStatItem(
    value: String,
    label: String,
    modifier: Modifier = Modifier
) {
    Column(
        modifier = modifier.padding(horizontal = 8.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = value,
            fontSize = 18.sp,
            fontWeight = FontWeight.Bold,
            color = Color.Black,
            textAlign = TextAlign.Center
        )
        Spacer(modifier = Modifier.height(4.dp))
        Text(
            text = label,
            fontSize = 12.sp,
            color = Color.Gray,
            textAlign = TextAlign.Center
        )
    }
}

// л ҲлІЁлӘ… н•ЁмҲҳ
private fun getLevelName(days: Int): String {
    return when {
        days < 7 -> "мӢңмһ‘"
        days < 30 -> "мһ‘мӢ¬ 7мқј"
        days < 90 -> "н•ң лӢ¬ нҒҙлҰ¬м–ҙ"
        days < 365 -> "3к°ңмӣ” нҒҙлҰ¬м–ҙ"
        else -> "м Ҳм ңмқҳ л Ҳм „л“ң"
    }
}

@Preview(showBackground = true)
@Composable
fun PreviewCardDetailScreen() {
    CardDetailScreen(
        startTime = System.currentTimeMillis() - (7 * 24 * 60 * 60 * 1000L),
        endTime = System.currentTimeMillis(),
        targetDays = 30f,
        actualDays = 7,
        isCompleted = true,
        onBack = {}
    )
}

package com.example.alcoholictimer

import android.content.Context
import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.tooling.preview.Preview
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import java.text.SimpleDateFormat
import java.util.*
import kotlin.math.roundToInt

/**
 * кёҲмЈј кё°лЎқ м№ҙл“ңмқҳ мғҒм„ё м •ліҙлҘј н‘ңмӢңн•ҳлҠ” м•ЎнӢ°л№„нӢ°
 * DetailActivityмҷҖ кө¬л¶„н•ҳм—¬ м№ҙл“ң нҒҙлҰӯ мӢң н‘ңмӢңлҗҳлҠ” нҷ”л©ҙмңјлЎң мӮ¬мҡ©
 */
class CardDetailActivity : ComponentActivity() {

    companion object {
        private const val TAG = "CardDetailActivity"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        Log.d(TAG, "===== CardDetailActivity onCreate мӢңмһ‘ =====")

        try {
            // Intentм—җм„ң лҚ°мқҙн„° л°ӣкё° (м•Ҳм „н•ң л°©мӢқмңјлЎң)
            val startTime = intent.getLongExtra("start_time", 0L)
            val endTime = intent.getLongExtra("end_time", System.currentTimeMillis())
            val targetDays = intent.getFloatExtra("target_days", 30f)
            val actualDays = intent.getIntExtra("actual_days", 0)
            val isCompleted = intent.getBooleanExtra("is_completed", false)

            Log.d(TAG, "мҲҳмӢ лҗң лҚ°мқҙн„°: startTime=$startTime, endTime=$endTime, targetDays=$targetDays, actualDays=$actualDays, isCompleted=$isCompleted")

            // лҚ°мқҙн„° мң нҡЁм„ұ кІҖмӮ¬ (лҚ” кҙҖлҢҖн•ҳкІҢ)
            if (actualDays < 0) {
                Log.e(TAG, "мһҳлӘ»лҗң лҚ°мқҙн„°: actualDays=$actualDays")
                finish()
                return
            }

            // targetDaysк°Җ 0 мқҙн•ҳмқё кІҪмҡ° кё°ліёк°’мңјлЎң м„Өм •
            val safeTargetDays = if (targetDays <= 0) 30f else targetDays
            // actualDaysк°Җ 0мқё кІҪмҡ°лҸ„ н—Ҳмҡ©н•ҳлҗҳ, мөңмҶҢ 1лЎң кі„мӮ°м—җ мӮ¬мҡ©
            val safeActualDays = if (actualDays <= 0) 1 else actualDays

            Log.d(TAG, "м•Ҳм „н•ң к°’л“Ө: targetDays=$safeTargetDays, actualDays=$safeActualDays")

            Log.d(TAG, "setContent нҳём¶ң мӢңмһ‘...")
            setContent {
                CardDetailScreen(
                    startTime = startTime,
                    endTime = endTime,
                    targetDays = safeTargetDays,
                    actualDays = safeActualDays,
                    isCompleted = isCompleted,
                    onBack = {
                        Log.d(TAG, "л’ӨлЎңк°Җкё° лІ„нҠј нҒҙлҰӯ")
                        finish()
                    }
                )
            }
            Log.d(TAG, "setContent нҳём¶ң мҷ„лЈҢ")
            Log.d(TAG, "===== CardDetailActivity onCreate мҷ„лЈҢ =====")
        } catch (e: Exception) {
            Log.e(TAG, "CardDetailActivity мҙҲкё°нҷ” мӨ‘ мҳӨлҘҳ", e)
            Log.e(TAG, "мҳӨлҘҳ мҠӨнғқнҠёл ҲмқҙмҠӨ: ${e.stackTraceToString()}")
            finish()
        }
    }
}

@Composable
fun CardDetailScreen(
    startTime: Long,
    endTime: Long,
    targetDays: Float,
    actualDays: Int,
    isCompleted: Boolean,
    onBack: () -> Unit
) {
    val context = LocalContext.current

    // лӮ м§ң/мӢңк°„ нҸ¬л§·
    val dateTimeFormat = SimpleDateFormat("yyyy-MM-dd - a h:mm", Locale.getDefault())
    val displayDateTime = if (startTime > 0) {
        dateTimeFormat.format(Date(startTime))
    } else {
        "мҳӨлҠҳ - ${SimpleDateFormat("a h:mm", Locale.getDefault()).format(Date())}"
    }

    // кё°лЎқ м ңлӘ© мһҗлҸҷ мғқм„ұ
    val recordTitle = if (isCompleted) {
        "кёҲмЈј ${actualDays}мқј лӢ¬м„ұ кё°лЎқ"
    } else {
        "кёҲмЈј ${actualDays}мқјм°Ё мӨ‘лӢЁ кё°лЎқ"
    }

    // кёҲмЈј кё°к°„ кі„мӮ°
    val totalDuration = if (startTime > 0) {
        ((endTime - startTime) / (24 * 60 * 60 * 1000)).toInt()
    } else {
        actualDays
    }

    // м„Өм •к°’ к°Җм ёмҳӨкё° (м Ҳм•Ҫ кёҲм•Ў/мӢңк°„ кі„мӮ°мҡ©)
    val sharedPref = context.getSharedPreferences("user_settings", Context.MODE_PRIVATE)
    val selectedCost = sharedPref.getString("selected_cost", "мӨ‘") ?: "мӨ‘"
    val selectedFrequency = sharedPref.getString("selected_frequency", "мЈј 2~3нҡҢ") ?: "мЈј 2~3нҡҢ"
    val selectedDuration = sharedPref.getString("selected_duration", "ліҙнҶө") ?: "ліҙнҶө"

    // м Ҳм•Ҫ кёҲм•Ў/мӢңк°„ кі„мӮ°
    val costVal = when(selectedCost) {
        "м Җ" -> 10000
        "мӨ‘" -> 40000
        "кі " -> 70000
        else -> 40000
    }

    val freqVal = when(selectedFrequency) {
        "мЈј 1нҡҢ мқҙн•ҳ" -> 1.0
        "мЈј 2~3нҡҢ" -> 2.5
        "мЈј 4нҡҢ мқҙмғҒ" -> 5.0
        else -> 2.5
    }

    val drinkHoursVal = when(selectedDuration) {
        "м§§мқҢ" -> 2
        "ліҙнҶө" -> 4
        "к№Җ" -> 6
        else -> 4
    }

    val hangoverHoursVal = 5
    val weeks = actualDays / 7.0
    val savedMoney = (weeks * freqVal * costVal).roundToInt()
    val savedHours = (weeks * freqVal * (drinkHoursVal + hangoverHoursVal)).roundToInt()

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
            .padding(24.dp)
    ) {
        // н—ӨлҚ” мҳҒм—ӯ
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // л’ӨлЎңк°Җкё° лІ„нҠј
            Box(
                contentAlignment = Alignment.Center,
                modifier = Modifier
                    .size(40.dp)
                    .background(Color.LightGray, CircleShape)
                    .clickable { onBack() }
            ) {
                Text(
                    text = "вҶҗ",
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Bold
                )
            }

            Text(
                text = "кёҲмЈј кё°лЎқ мғҒм„ё",
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold
            )

            Spacer(modifier = Modifier.width(40.dp)) // к· нҳ• л§һм¶”кё°
        }

        Spacer(modifier = Modifier.height(32.dp))

        // лӮ м§ң л°Ҹ мӢңк°„
        Text(
            text = displayDateTime,
            fontSize = 16.sp,
            color = Color.Gray,
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        // кё°лЎқ м ңлӘ©
        Text(
            text = recordTitle,
            fontSize = 20.sp,
            fontWeight = FontWeight.Bold,
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(40.dp))

        // мЈјмҡ” нҶөкі„ мҳҒм—ӯ
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            // мҷјмӘҪ лҢҖнҳ• мҲ«мһҗ
            Column(
                modifier = Modifier.weight(1f),
                horizontalAlignment = Alignment.Start
            ) {
                Text(
                    text = actualDays.toString(),
                    fontSize = 72.sp,
                    fontWeight = FontWeight.Bold,
                    color = Color.Black,
                    lineHeight = 72.sp
                )
                Text(
                    text = "мқј",
                    fontSize = 16.sp,
                    color = Color.Gray
                )
            }

            // мҳӨлҘёмӘҪ м„ұм·Ё м•„мқҙмҪҳ
            Column(
                modifier = Modifier.weight(1f),
                horizontalAlignment = Alignment.End
            ) {
                Text(
                    text = if (isCompleted) "" else "вҸёпёҸ",
                    fontSize = 60.sp
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = if (isCompleted) "лӘ©н‘ң лӢ¬м„ұ" else "мӨ‘лӢЁлҗЁ",
                    fontSize = 14.sp,
                    color = if (isCompleted) Color(0xFF4CAF50) else Color(0xFFFF9800),
                    fontWeight = FontWeight.Bold
                )
            }
        }

        Spacer(modifier = Modifier.height(32.dp))

        // м„ңлёҢ нҶөкі„ (2мӨ„ л°°м№ҳ)
        Column {
            // мІ« лІҲм§ё мӨ„
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceEvenly
            ) {
                CardSubStatItem(
                    value = "${totalDuration}мқј",
                    label = "мҙқ кёҲмЈј кё°к°„",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = String.format(Locale.getDefault(), "%,dмӣҗ", savedMoney),
                    label = "м Ҳм•Ҫн•ң кёҲм•Ў",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = "${savedHours}мӢңк°„",
                    label = "м Ҳм•Ҫн•ң мӢңк°„",
                    modifier = Modifier.weight(1f)
                )
            }

            Spacer(modifier = Modifier.height(24.dp))

            // л‘җ лІҲм§ё мӨ„
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceEvenly
            ) {
                CardSubStatItem(
                    value = "${((actualDays.toFloat() / targetDays) * 100).roundToInt()}%",
                    label = "лӘ©н‘ң лӢ¬м„ұлҘ ",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = getLevelName(actualDays),
                    label = "лӢ¬м„ұ л ҲлІЁ",
                    modifier = Modifier.weight(1f)
                )
                CardSubStatItem(
                    value = "${(actualDays / 30.0).roundToInt()}мқј",
                    label = "кё°лҢҖ мҲҳлӘ… мҰқк°Җ",
                    modifier = Modifier.weight(1f)
                )
            }
        }

        Spacer(modifier = Modifier.weight(1f))

        // н•ҳлӢЁ лІ„нҠј
        Button(
            onClick = { onBack() },
            modifier = Modifier
                .fillMaxWidth()
                .height(56.dp),
            colors = ButtonDefaults.buttonColors(
                containerColor = Color.Black
            )
        ) {
            Text(
                text = "нҷ•мқё",
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold,
                color = Color.White
            )
        }
    }
}

@Composable
private fun CardSubStatItem(
    value: String,
    label: String,
    modifier: Modifier = Modifier
) {
    Column(
        modifier = modifier.padding(horizontal = 8.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = value,
            fontSize = 18.sp,
            fontWeight = FontWeight.Bold,
            color = Color.Black,
            textAlign = TextAlign.Center
        )
        Spacer(modifier = Modifier.height(4.dp))
        Text(
            text = label,
            fontSize = 12.sp,
            color = Color.Gray,
            textAlign = TextAlign.Center
        )
    }
}

// л ҲлІЁлӘ… н•ЁмҲҳ
private fun getLevelName(days: Int): String {
    return when {
        days < 7 -> "мӢңмһ‘"
        days < 30 -> "мһ‘мӢ¬ 7мқј"
        days < 90 -> "н•ң лӢ¬ нҒҙлҰ¬м–ҙ"
        days < 365 -> "3к°ңмӣ” нҒҙлҰ¬м–ҙ"
        else -> "м Ҳм ңмқҳ л Ҳм „л“ң"
    }
}

