        val sharedPref = getSharedPreferences("user_settings", MODE_PRIVATE)
        val isSobrietyStarted = sharedPref.contains("start_time")

        if (isSobrietyStarted) {
            // кёҲмЈјк°Җ м§„н–ү мӨ‘мқҙл©ҙ StatusActivityлЎң мқҙлҸҷ
            val intent = Intent(this, StatusActivity::class.java)
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
            startActivity(intent)
            overridePendingTransition(0, 0)
        } else {
            // кёҲмЈјк°Җ мӢңмһ‘лҗҳм§Җ м•Ҡм•ҳмңјл©ҙ StartActivityлЎң мқҙлҸҷ
            val intent = Intent(this, StartActivity::class.java)
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
            startActivity(intent)
            overridePendingTransition(0, 0)
        }
        // MainActivityлҠ” л°ұмҠӨнғқм—җм„ң м ңкұ°
        finish()
        overridePendingTransition(0, 0)
    }

    @Preview(showBackground = true)
    @Composable
    fun PreviewMainScreen() {
        MainScreen()
    }
}

