/**
 * л¶ҷм—¬л„Јкё° кё°лҠҘмқҙ л№„нҷңм„ұнҷ”лҗң м»ӨмҠӨн…Җ EditText
 */
class NoPasteEditText : EditText {
    constructor(context: Context) : super(context) {
        init()
    }

    constructor(context: Context, attrs: AttributeSet?) : super(context, attrs) {
        init()
    }

    constructor(context: Context, attrs: AttributeSet?, defStyleAttr: Int) : super(context, attrs, defStyleAttr) {
        init()
    }

    private fun init() {
        // кёёкІҢ лҲ„лҘҙкё° л№„нҷңм„ұнҷ”
        isLongClickable = false

        // н…ҚмҠӨнҠё м„ нғқ л№„нҷңм„ұнҷ”
        setTextIsSelectable(false)

        // м»Ён…ҚмҠӨнҠё л©”лүҙ л№„нҷңм„ұнҷ”
        customSelectionActionModeCallback = object : ActionMode.Callback {
            override fun onCreateActionMode(mode: ActionMode?, menu: Menu?): Boolean = false
            override fun onPrepareActionMode(mode: ActionMode?, menu: Menu?): Boolean = false
            override fun onActionItemClicked(mode: ActionMode?, item: MenuItem?): Boolean = false
            override fun onDestroyActionMode(mode: ActionMode?) {}
        }
    }

    override fun onTextContextMenuItem(id: Int): Boolean {
        // лӘЁл“  м»Ён…ҚмҠӨнҠё л©”лүҙ н•ӯлӘ©(л¶ҷм—¬л„Јкё°, ліөмӮ¬ л“ұ) м°ЁлӢЁ
        return false
    }

    override fun onCreateInputConnection(outAttrs: EditorInfo): InputConnection {
        val connection = super.onCreateInputConnection(outAttrs)

        // IME мҳөм…ҳ м„Өм •
        outAttrs.imeOptions = outAttrs.imeOptions or
                EditorInfo.IME_FLAG_NO_EXTRACT_UI or
                EditorInfo.IME_FLAG_NO_FULLSCREEN

        return connection
    }

    // л¶ҷм—¬л„Јкё° л°©м§ҖлҘј мң„н•ҙ лӘЁл“  мһ…л Ҙ мӢңлҸ„лҘј м¶”к°ҖлЎң кІҖмӮ¬
    override fun onTextChanged(text: CharSequence?, start: Int, lengthBefore: Int, lengthAfter: Int) {
        super.onTextChanged(text, start, lengthBefore, lengthAfter)

        // н…ҚмҠӨнҠёк°Җ н•ң лІҲм—җ м—¬лҹ¬ мһҗлҰ¬ м¶”к°ҖлҗҳлҠ” кІҪмҡ° (л¶ҷм—¬л„Јкё°лЎң м¶”м •)
        if (lengthAfter > 1 && lengthBefore == 0) {
            val currentText = this.text.toString()
            if (start == 0 && currentText.length > 1) {
                // л§Ҳм§Җл§ү мҲ«мһҗл§Ң мң м§Җ
                setText(currentText.substring(currentText.length - 1))
            }
        }
    }
}

// Jetpack Compose кё°л°ҳмңјлЎң UIлҘј мҷ„м „нһҲ м „нҷҳн•ң кІҪмҡ°, мқҙ нҢҢмқјмқҖ лҚ” мқҙмғҒ н•„мҡ”н•ҳм§Җ м•ҠмңјлҜҖлЎң мӮӯм ңн•ҙлҸ„ лҗ©лӢҲлӢӨ.
