import android.os.Bundle;
import android.os.Handler;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import com.example.alcoholictimer.R; // R нҒҙлһҳмҠӨ import м¶”к°Җ
import com.google.android.material.floatingactionbutton.FloatingActionButton;

import java.util.Locale;

public class SoberScreenActivity extends AppCompatActivity {
    private Handler handler = new Handler();
    private int elapsedSeconds = 0;
    private boolean isTimerRunning = false;
    private TextView tvTimeDetail; // ліҖмҲҳлӘ… ліҖкІҪ

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.content_status);

        tvTimeDetail = findViewById(R.id.tvTimeDetail); // ID ліҖкІҪ

        // нғҖмқҙлЁё мӢңмһ‘ лІ„нҠј м„Өм •
        FloatingActionButton btnStartTimer = findViewById(R.id.btnStopSobriety);
        btnStartTimer.setOnClickListener(v -> {
            if (!isTimerRunning) {
                startTimer();
            }
        });
    }

    private void startTimer() {
        elapsedSeconds = 0; // нғҖмқҙлЁё мҙҲкё°нҷ”
        isTimerRunning = true; // нғҖмқҙлЁё мғҒнғң ліҖкІҪ
        handler.post(timerRunnable); // Runnable мӢӨн–ү
    }

    private final Runnable timerRunnable = new Runnable() {
        @Override
        public void run() {
            if (isTimerRunning) {
                int minutes = elapsedSeconds / 60;
                int seconds = elapsedSeconds % 60;
                tvTimeDetail.setText(String.format(Locale.getDefault(), "%02d:%02d", minutes, seconds));
                elapsedSeconds++;
                handler.postDelayed(this, 1000); // 1мҙҲл§ҲлӢӨ м—…лҚ°мқҙнҠё
            }
        }
    };

    @Override
    protected void onDestroy() {
        super.onDestroy();
        handler.removeCallbacks(timerRunnable); // н•ёл“Өлҹ¬ мҪңл°ұ м ңкұ°
        isTimerRunning = false; // нғҖмқҙлЁё мғҒнғң мҙҲкё°нҷ”
    }

    // мҳҲ: кІ°кіј нҷ”л©ҙмңјлЎң л„ҳм–ҙк°Җкё° мң„н•ң л”ңл Ҳмқҙ мҪ”л“ң
    handler.postDelayed(new Runnable() {
        @Override
        public void run() {
            // ...нҷ”л©ҙ м „нҷҳ мҪ”л“ң...
        }
    }, 2000); // ліҖкІҪ: кё°мЎҙ 3000 -> 2000
}

