data class WeekOption(
    val startTime: Long,
    val endTime: Long,
    val displayText: String
)

private fun generateWeekOptions(): List<WeekOption> {
    val calendar = Calendar.getInstance()
    val dateFormat = SimpleDateFormat("MM-dd", Locale.getDefault())
    val options = mutableListOf<WeekOption>()

    // мқҙлІҲ мЈјл¶Җн„° мӢңмһ‘н•ҙм„ң кіјкұ°лЎң кұ°мҠ¬лҹ¬ мҳ¬лқјк°Җл©ҙм„ң лҚ°мқҙн„° мғқм„ұ
    calendar.firstDayOfWeek = Calendar.MONDAY
    calendar.set(Calendar.DAY_OF_WEEK, Calendar.MONDAY)
    calendar.set(Calendar.HOUR_OF_DAY, 0)
    calendar.set(Calendar.MINUTE, 0)
    calendar.set(Calendar.SECOND, 0)
    calendar.set(Calendar.MILLISECOND, 0)

    for (i in 0 until 8) { // мөңк·ј 8мЈј
        val weekStart = calendar.timeInMillis
        calendar.add(Calendar.DAY_OF_WEEK, 6) // мқјмҡ”мқјлЎң мқҙлҸҷ
        val weekEnd = calendar.timeInMillis

        val startDate = dateFormat.format(Date(weekStart))
        val endDate = dateFormat.format(Date(weekEnd))

        val displayText = when (i) {
            0 -> "мқҙлІҲ мЈј"
            1 -> "м§ҖлӮң мЈј"
            else -> "$startDate ~ $endDate"
        }

        options.add(WeekOption(weekStart, weekEnd, displayText))

        // лӢӨмқҢ мЈјлЎң мқҙлҸҷ (мӢӨм ңлЎңлҠ” мқҙм „ мЈј)
        calendar.add(Calendar.DAY_OF_WEEK, -13) // мқјмҡ”мқјм—җм„ң мқҙм „ мЈј мӣ”мҡ”мқјлЎң
    }

    // кіјкұ°м—җм„ң нҳ„мһ¬ мҲңмңјлЎң м •л ¬ (reverse)
    return options.reversed()
}

