package com.example.alcoholictimer.models

/**
 * мөңк·ј нҷңлҸҷ лҚ°мқҙн„° нҒҙлһҳмҠӨ
 * кёҲмЈј мҷ„лЈҢ/мӨ‘лӢЁ кё°лЎқмқ„ лӮҳнғҖлғ…лӢҲлӢӨ.
 */
data class RecentActivity(
    val startDate: String,
    val endDate: String,
    val title: String,
    val duration: Int,
    val hours: Int,
    val isSuccess: Boolean,
    val savedMoney: Int,
    val testMode: Int
) {
    /**
     * н‘ңмӢңмҡ© мғҒнғң н…ҚмҠӨнҠё л°ҳнҷҳ
     */
    fun getDisplayStatus(): String {
        return if (isSuccess) "мҷ„лЈҢ" else "мӨ‘м§Җ"
    }

    /**
     * м„ұкіөлҘ мқ„ нҚјм„јнҠёлЎң л°ҳнҷҳ
     */
    fun getSuccessRate(): Int {
        return if (duration > 0) {
            ((hours / 24.0 / duration) * 100).toInt()
        } else {
            0
        }
    }
}

package com.example.alcoholictimer.models

import org.json.JSONArray
import org.json.JSONObject

/**
 * мөңк·ј нҷңлҸҷ лҚ°мқҙн„° нҒҙлһҳмҠӨ
 * кёҲмЈј мҷ„лЈҢ/мӨ‘лӢЁ кё°лЎқмқ„ лӮҳнғҖлғ…лӢҲлӢӨ.
 */
data class RecentActivity(
    val startDate: String,
    val endDate: String,
    val title: String,
    val duration: Int,
    val hours: Int,
    val isSuccess: Boolean,
    val savedMoney: Int,
    val testMode: Int
) {
    /**
     * н‘ңмӢңмҡ© мғҒнғң н…ҚмҠӨнҠё л°ҳнҷҳ
     */
    fun getDisplayStatus(): String {
        return if (isSuccess) "мҷ„лЈҢ" else "мӨ‘м§Җ"
    }

    /**
     * м„ұкіөлҘ мқ„ нҚјм„јнҠёлЎң л°ҳнҷҳ
     */
    fun getSuccessRate(): Int {
        return if (duration > 0) {
            ((hours / 24.0 / duration) * 100).toInt()
        } else {
            0
        }
    }

    /**
     * JSON к°қмІҙлЎң ліҖнҷҳ
     */
    fun toJson(): JSONObject {
        return JSONObject().apply {
            put("startDate", startDate)
            put("endDate", endDate)
            put("title", title)
            put("duration", duration)
            put("hours", hours)
            put("isSuccess", isSuccess)
            put("savedMoney", savedMoney)
            put("testMode", testMode)
        }
    }

    companion object {
        /**
         * JSON к°қмІҙм—җм„ң RecentActivity мғқм„ұ
         */
        fun fromJson(json: JSONObject): RecentActivity {
            return RecentActivity(
                startDate = json.getString("startDate"),
                endDate = json.getString("endDate"),
                title = json.getString("title"),
                duration = json.getInt("duration"),
                hours = json.getInt("hours"),
                isSuccess = json.getBoolean("isSuccess"),
                savedMoney = json.getInt("savedMoney"),
                testMode = json.getInt("testMode")
            )
        }

        /**
         * JSON л°°м—ҙ л¬ёмһҗм—ҙм—җм„ң RecentActivity лҰ¬мҠӨнҠё мғқм„ұ
         */
        fun fromJsonArray(jsonString: String): List<RecentActivity> {
            return try {
                val jsonArray = JSONArray(jsonString)
                val activities = mutableListOf<RecentActivity>()

                for (i in 0 until jsonArray.length()) {
                    val jsonObject = jsonArray.getJSONObject(i)
                    activities.add(fromJson(jsonObject))
                }

                activities
            } catch (e: Exception) {
                emptyList()
            }
        }

        /**
         * RecentActivity лҰ¬мҠӨнҠёлҘј JSON л°°м—ҙ л¬ёмһҗм—ҙлЎң ліҖнҷҳ
         */
        fun toJsonArray(activities: List<RecentActivity>): String {
            return try {
                val jsonArray = JSONArray()
                activities.forEach { activity ->
                    jsonArray.put(activity.toJson())
                }
                jsonArray.toString()
            } catch (e: Exception) {
                "[]"
            }
        }
    }
}

package com.example.alcoholictimer.utils

import android.content.Context
import android.content.SharedPreferences
import com.example.alcoholictimer.models.RecentActivity
import java.text.SimpleDateFormat
import java.util.*

object RecordManager {
    private const val PREFS_NAME = "recent_activities"
    private const val KEY_ACTIVITIES = "activities"

    private lateinit var prefs: SharedPreferences

    fun init(context: Context) {
        prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    }

    fun addActivity(activity: RecentActivity) {
        // к°„лӢЁн•ң л¬ёмһҗм—ҙ нҳ•нғңлЎң м ҖмһҘ
        val activities = getActivities().toMutableList()
        activities.add(0, activity) // мөңмӢ  нҷңлҸҷмқ„ л§Ё м•һм—җ м¶”к°Җ

        // мөңлҢҖ 5к°ңл§Ң мң м§Җ
        while (activities.size > 5) {
            activities.removeLast()
        }

        // к°„лӢЁн•ң л¬ёмһҗм—ҙ м ҖмһҘ л°©мӢқ мӮ¬мҡ©
        val activitiesString = activities.joinToString("|") {
            "${it.startDate},${it.endDate},${it.duration},${it.isSuccess}"
        }
        prefs.edit().putString(KEY_ACTIVITIES, activitiesString).apply()
    }

    fun getActivities(): List<RecentActivity> {
        val activitiesString = prefs.getString(KEY_ACTIVITIES, "") ?: ""
        if (activitiesString.isEmpty()) return emptyList()

        return activitiesString.split("|").mapNotNull { activityData ->
            val parts = activityData.split(",")
            if (parts.size == 4) {
                RecentActivity(
                    startDate = parts[0],
                    endDate = parts[1],
                    duration = parts[2].toIntOrNull() ?: 0,
                    isSuccess = parts[3].toBoolean()
                )
            } else null
        }
    }

    fun clearActivities() {
        prefs.edit().remove(KEY_ACTIVITIES).apply()
    }

    private fun getCurrentDate(): String {
        val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
        return dateFormat.format(Date())
    }
}

