package com.yourpackage.alcoholictimer

import android.content.Context
import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.runtime.collectAsState
import androidx.compose.runtime.getValue
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewmodel.compose.viewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow

class GraphActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContent {
            GraphScreen()
        }
    }
}

class GraphViewModel(context: Context) : ViewModel() {
    private val _weeklyRecords = MutableStateFlow(listOf(0, 0, 0, 0, 0, 0, 0))
    val weeklyRecords: StateFlow<List<Int>> = _weeklyRecords

    init {
        // SharedPreferencesм—җм„ң кёҲмЈј кё°лЎқ лҚ°мқҙн„° л¶Ҳлҹ¬мҳӨкё° (мҳҲмӢң)
        val prefs = context.getSharedPreferences("records_prefs", Context.MODE_PRIVATE)
        val records = (0..6).map { day ->
            prefs.getInt("record_day_$day", 0)
        }
        _weeklyRecords.value = records
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun GraphScreen() {
    val context = LocalContext.current
    val viewModel: GraphViewModel = ViewModelProvider(context as ComponentActivity).get(GraphViewModel::class.java)
    val weeklyRecords by viewModel.weeklyRecords.collectAsState()
    Scaffold(
        topBar = {
            TopAppBar(title = { Text("кёҲмЈј кё°лЎқ к·ёлһҳн”„") })
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            BarChart(
                data = weeklyRecords,
                modifier = Modifier
                    .fillMaxWidth()
                    .height(200.dp)
                    .padding(16.dp)
            )
        }
    }
}

// BarChart м»ҙнҸ¬м Җлё” кө¬нҳ„
@Composable
fun BarChart(data: List<Int>, modifier: Modifier = Modifier) {
    Row(
        modifier = modifier,
        horizontalArrangement = Arrangement.SpaceEvenly
    ) {
        data.forEach { value ->
            Box(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxHeight()
                    .padding(horizontal = 4.dp),
                contentAlignment = Alignment.BottomCenter
            ) {
                Box(
                    modifier = Modifier
                        .width(24.dp)
                        .height((value * 20).dp)
                        .background(MaterialTheme.colorScheme.primary)
                )
            }
        }
    }
}

